from pathlib import Path
from miniaptly import MiniAptly, ArchiveError, parse_package
import tempfile

def make_archive(td):
    try:
        return MiniAptly()
    except TypeError:
        return MiniAptly(Path(td) / 'archive-root')

def make_pkg(td, name, version, arch='amd64', depends='', payload=None):
    payload = (payload if payload is not None else f'{name}-{version}-{arch}').encode('utf-8')
    path = Path(td) / f'{name}-{version}-{arch}-{abs(hash(payload))}.pkg'
    path.write_bytes((f'Name: {name}\nVersion: {version}\nArch: {arch}\nDepends: {depends}\n\n').encode('utf-8') + payload)
    return path

def deps(record):
    value = record.get('depends', [])
    if isinstance(value, str):
        return [part.strip() for part in value.split(',') if part.strip()]
    return list(value)

def ids(rows):
    return [(r['name'], r['version'], r['arch']) for r in rows]

def prefix_has(value, *parts):
    text = '' if value is None else str(value)
    return all(part in text for part in parts)

def _match(value, expected):
    if expected is None:
        return True
    if isinstance(expected, (tuple, list, set)):
        return value in expected
    return value == expected

def graph_has(edges, *, from_type=None, to_type=None, from_contains=(), to=None):
    for edge in edges:
        if not _match(edge.get('from_type'), from_type):
            continue
        if not _match(edge.get('to_type'), to_type):
            continue
        if to is not None and edge.get('to') != to:
            continue
        if all(part in str(edge.get('from', '')) for part in from_contains):
            return True
    return False

def graph_has_any_to(edges, targets, **kwargs):
    return any(graph_has(edges, to=target, **kwargs) for target in targets)

def cleanup_keep(report):
    keep = report.get('keep', {})
    if isinstance(keep, dict):
        return set(keep.keys())
    return set(keep)

def cleanup_remove(report):
    return set(report.get('remove', []))

def cleanup_blocked(report):
    blocked = report.get('blocked', {})
    return bool(blocked)

def changed_versions(diff):
    out = []
    for item in diff.get('changed', []):
        before = item.get('before') or item.get('from') or item.get('old')
        after = item.get('after') or item.get('to') or item.get('new')
        if isinstance(before, dict) and isinstance(after, dict):
            out.append((before.get('version'), after.get('version')))
    return sorted(out)

